1	import { useState, useEffect } from "react";
2	import { useSearchParams } from "react-router-dom";
3	import { supabase } from "@/integrations/supabase/client";
4	import { Link2, MessageSquare, Sparkles, Settings, Receipt, FileSignature } from "lucide-react";
5	import { motion, AnimatePresence } from "framer-motion";
6	import { cn } from "@/lib/utils";
7	import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
8	
9	// Tab content
10	import CreviaLink from "./CreviaLink";
11	import SmartInvoicesTab from "@/components/studio/SmartInvoicesTab";
12	import ContractsTab from "@/components/studio/ContractsTab";
13	import StudioSettingsTab from "@/components/studio/StudioSettingsTab";
14	import StudioWorkspacesHub from "@/components/studio/workspaces/StudioWorkspacesHub";
15	
16	const CreviaStudio = () => {
17	  const [searchParams, setSearchParams] = useSearchParams();
18	  const [loading, setLoading] = useState(true);
19	
20	  const activeTab = searchParams.get("tab") || "link";
21	  const activeLinkSection = searchParams.get("section") || "profile";
22	  const activeWorkspace = searchParams.get("workspace") || undefined;
23	
24	  useEffect(() => {
25	    const checkUser = async () => {
26	      const { data: { session } } = await supabase.auth.getSession();
27	      if (session) {
28	        const { data: profile } = await supabase
29	          .from("profiles")
30	          .select("user_type")
31	          .eq("id", session.user.id)
32	          .single();
33	      }
34	      setLoading(false);
35	    };
36	    checkUser();
37	  }, []);
38	
39	  // Strict order: Link → Workspace → Invoice → Contracts → Settings
40	  const studioTabs = [
41	    { id: "link",      label: "Crevia Link", icon: Link2 },
42	    { id: "chat",      label: "Workspace",   icon: MessageSquare },
43	    { id: "invoices",  label: "Invoice",     icon: Receipt },
44	    { id: "contracts", label: "Contracts",   icon: FileSignature },
45	    { id: "settings",  label: "Settings",    icon: Settings },
46	  ];
47	
48	  const linkSections = [
49	    { id: "profile",    label: "Profile" },
50	    { id: "buttons",    label: "Buttons" },
51	    { id: "appearance", label: "Appearance" },
52	    { id: "settings",   label: "Settings" },
53	    { id: "analytics",  label: "Analytics" },
54	  ];
55	
56	  const handleTabChange = (tabId: string) => {
57	    setSearchParams({ tab: tabId });
58	  };
59	
60	  const handleLinkSectionChange = (sectionId: string) => {
61	    setSearchParams({ tab: "link", section: sectionId });
62	  };
63	
64	  if (loading) {
65	    return (
66	      <div className="min-h-screen bg-background flex items-center justify-center">
67	        <div className="text-muted-foreground font-poppins">Loading...</div>
68	      </div>
69	    );
70	  }
71	
72	  const isChatTab = activeTab === "chat";
73	
74	  return (
75	    <div className={cn(
76	      "bg-background",
77	      isChatTab
78	        ? "h-[calc(100vh-128px)] md:h-[calc(100vh-64px)] flex flex-col overflow-hidden"
79	        : "min-h-screen overflow-x-hidden"
80	    )}>
81	      {/* Studio Header */}
82	      <div className={cn(
83	        "border-b border-border bg-background z-30 flex-shrink-0",
84	        !isChatTab && "md:sticky md:top-0"
85	      )}>
86	        <div className="mx-auto w-full max-w-7xl px-4 py-3 md:px-6 md:py-4">
87	          <div className="flex items-center gap-3 mb-3 md:mb-4">
88	            <div className="p-1.5 md:p-2 rounded-xl bg-bronze/10">
89	              <Sparkles className="h-4 w-4 md:h-5 md:w-5 text-bronze" />
90	            </div>
91	            <div>
92	              <h1 className="font-vollkorn text-xl md:text-2xl font-semibold text-foreground">
93	                Crevia Studio
94	              </h1>
95	              <p className="text-xs md:text-sm text-muted-foreground">
96	                Your creative business toolkit
97	              </p>
98	            </div>
99	          </div>
100	
101	          {/* Tabs — strict order enforced by studioTabs array */}
102	          <ScrollArea className="w-full">
103	            <div className="flex items-center gap-1 pb-1 -mb-px">
104	              {studioTabs.map((tab) => {
105	                const Icon = tab.icon;
106	                const isActive = activeTab === tab.id;
107	                return (
108	                  <button
109	                    key={tab.id}
110	                    onClick={() => handleTabChange(tab.id)}
111	                    className={cn(
112	                      "flex items-center gap-1.5 px-3 py-2 rounded-t-lg font-poppins text-xs sm:text-sm font-medium whitespace-nowrap transition-all duration-300",
113	                      isActive
114	                        ? "bg-bronze/10 text-bronze border-b-2 border-bronze"
115	                        : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
116	                    )}
117	                  >
118	                    <Icon className="h-4 w-4 flex-shrink-0" />
119	                    <span>{tab.label}</span>
120	                  </button>
121	                );
122	              })}
123	            </div>
124	            <ScrollBar orientation="horizontal" className="h-1.5" />
125	          </ScrollArea>
126	
127	          {/* Link sub-sections (mobile only) */}
128	          {activeTab === "link" && (
129	            <div className="md:hidden mt-3 border-t border-border/40 pt-3">
130	              <ScrollArea className="w-full">
131	                <div className="flex items-center gap-2">
132	                  {linkSections.map((section) => (
133	                    <button
134	                      key={section.id}
135	                      type="button"
136	                      onClick={() => handleLinkSectionChange(section.id)}
137	                      className={cn(
138	                        "inline-flex items-center justify-center rounded-lg border px-4 py-2 text-sm font-medium whitespace-nowrap transition-colors",
139	                        activeLinkSection === section.id
140	                          ? "bg-primary text-primary-foreground border-primary"
141	                          : "bg-background text-muted-foreground border-border hover:bg-muted hover:text-foreground"
142	                      )}
143	                    >
144	                      {section.label}
145	                    </button>
146	                  ))}
147	                </div>
148	                <ScrollBar orientation="horizontal" className="h-1.5" />
149	              </ScrollArea>
150	            </div>
151	          )}
152	        </div>
153	      </div>
154	
155	      {/* Tab Content */}
156	      {isChatTab ? (
157	        <div className="flex-1 min-h-0 overflow-hidden">
158	          <StudioWorkspacesHub />
159	        </div>
160	      ) : (
161	        <div className="flex-1 min-w-0 overflow-x-hidden">
162	          <AnimatePresence mode="wait">
163	            <motion.div
164	              key={activeTab}
165	              initial={{ opacity: 0, y: 8 }}
166	              animate={{ opacity: 1, y: 0 }}
167	              exit={{ opacity: 0, y: -6 }}
168	              transition={{ duration: 0.3, ease: [0.25, 0.46, 0.45, 0.94] }}
169	            >
170	              {activeTab === "link"      && <CreviaLink isEmbedded />}
171	              {activeTab === "invoices"  && <SmartInvoicesTab workspaceId={activeWorkspace} />}
172	              {activeTab === "contracts" && <ContractsTab workspaceId={activeWorkspace} />}
173	              {activeTab === "settings"  && <StudioSettingsTab />}
174	            </motion.div>
175	          </AnimatePresence>
176	        </div>
177	      )}
178	    </div>
179	  );
180	};
181	
182	export default CreviaStudio;
183

1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import { Card } from "@/components/ui/card";
5	import { Input } from "@/components/ui/input";
6	import { 
7	  Plus, 
8	  Search, 
9	  FileSignature, 
10	  Eye,
11	  MoreHorizontal,
12	  Edit,
13	  Trash2,
14	  CheckCircle2,
15	  Clock,
16	  Send,
17	  FileText,
18	  XCircle,
19	  Users,
20	  Upload,
21	  Copy,
22	  Filter,
23	  ArrowUpDown,
24	  TrendingUp,
25	  Sparkles,
26	  File,
27	  CalendarDays
28	} from "lucide-react";
29	import { toast } from "sonner";
30	import { format } from "date-fns";
31	import { motion, AnimatePresence } from "framer-motion";
32	import {
33	  DropdownMenu,
34	  DropdownMenuContent,
35	  DropdownMenuItem,
36	  DropdownMenuSeparator,
37	  DropdownMenuTrigger,
38	} from "@/components/ui/dropdown-menu";
39	import {
40	  Select,
41	  SelectContent,
42	  SelectItem,
43	  SelectTrigger,
44	  SelectValue,
45	} from "@/components/ui/select";
46	import CreateContractDialog from "./CreateContractDialog";
47	import { useSubscription } from "@/hooks/use-subscription";
48	import UpgradePrompt from "@/components/subscription/UpgradePrompt";
49	import ContractPreviewDialog from "./ContractPreviewDialog";
50	import UploadContractDialog from "./UploadContractDialog";
51	
52	interface Contract {
53	  id: string;
54	  title: string;
55	  client_name: string;
56	  client_email: string | null;
57	  contract_type: string;
58	  status: string;
59	  start_date: string | null;
60	  end_date: string | null;
61	  value: number | null;
62	  currency: string;
63	  created_at: string;
64	  creator_signature: string | null;
65	  client_signature: string | null;
66	  content: string | null;
67	  deliverables: string[] | null;
68	  payment_terms: string | null;
69	  exclusivity: boolean | null;
70	  exclusivity_details: string | null;
71	  usage_rights: string | null;
72	  termination_clause: string | null;
73	}
74	
75	const contractTypeConfig: Record<string, { label: string; icon: string; gradient: string }> = {
76	  sponsorship: { label: "Sponsorship", icon: "💎", gradient: "from-violet-500/10 to-purple-500/5" },
77	  content_creation: { label: "Content", icon: "🎬", gradient: "from-blue-500/10 to-cyan-500/5" },
78	  brand_ambassador: { label: "Ambassador", icon: "🤝", gradient: "from-amber-500/10 to-orange-500/5" },
79	  ugc: { label: "UGC", icon: "📱", gradient: "from-green-500/10 to-emerald-500/5" },
80	  affiliate: { label: "Affiliate", icon: "🔗", gradient: "from-pink-500/10 to-rose-500/5" },
81	  custom: { label: "Custom", icon: "📄", gradient: "from-slate-500/10 to-gray-500/5" },
82	  uploaded: { label: "Uploaded", icon: "📎", gradient: "from-indigo-500/10 to-blue-500/5" },
83	};
84	
85	const statusConfig: Record<string, { label: string; color: string; bg: string; icon: React.ReactNode }> = {
86	  draft: { label: "Draft", color: "text-muted-foreground", bg: "bg-muted", icon: <FileText className="h-3 w-3" /> },
87	  sent: { label: "Sent", color: "text-blue-600 dark:text-blue-400", bg: "bg-blue-500/10", icon: <Send className="h-3 w-3" /> },
88	  signed: { label: "Signed", color: "text-emerald-600 dark:text-emerald-400", bg: "bg-emerald-500/10", icon: <FileSignature className="h-3 w-3" /> },
89	  active: { label: "Active", color: "text-green-600 dark:text-green-400", bg: "bg-green-500/10", icon: <CheckCircle2 className="h-3 w-3" /> },
90	  completed: { label: "Completed", color: "text-purple-600 dark:text-purple-400", bg: "bg-purple-500/10", icon: <CheckCircle2 className="h-3 w-3" /> },
91	  cancelled: { label: "Cancelled", color: "text-destructive", bg: "bg-destructive/10", icon: <XCircle className="h-3 w-3" /> },
92	};
93	
94	const ContractsTab = ({ workspaceId }: { workspaceId?: string } = {}) => {
95	  const [contracts, setContracts] = useState<Contract[]>([]);
96	  const [loading, setLoading] = useState(true);
97	  const [searchQuery, setSearchQuery] = useState("");
98	  const [statusFilter, setStatusFilter] = useState("all");
99	  const [sortBy, setSortBy] = useState<"newest" | "oldest" | "value">("newest");
100	  const { limits, isFree } = useSubscription();
101	  const [createDialogOpen, setCreateDialogOpen] = useState(false);
102	  const [editingContract, setEditingContract] = useState<Contract | null>(null);
103	  const [previewContract, setPreviewContract] = useState<Contract | null>(null);
104	  const [uploadDialogOpen, setUploadDialogOpen] = useState(false);
105	
106	  const fetchContracts = async () => {
107	    const { data: { session } } = await supabase.auth.getSession();
108	    if (!session) return;
109	
110	    if (workspaceId) {
111	      const { data: msgs } = await supabase
112	        .from("chat_messages")
113	        .select("contract_id")
114	        .eq("room_id", workspaceId)
115	        .not("contract_id", "is", null);
116	      const ids = [...new Set((msgs || []).map((m: any) => m.contract_id).filter(Boolean))];
117	      if (ids.length === 0) { setContracts([]); setLoading(false); return; }
118	      const { data, error } = await supabase.from("contracts").select("*").in("id", ids).order("created_at", { ascending: false });
119	      if (error) { toast.error("Failed to load contracts"); return; }
120	      setContracts(data || []);
121	      setLoading(false);
122	      return;
123	    }
124	
125	    const { data, error } = await supabase
126	      .from("contracts")
127	      .select("*")
128	      .eq("user_id", session.user.id)
129	      .order("created_at", { ascending: false });
130	
131	    if (error) {
132	      toast.error("Failed to load contracts");
133	      return;
134	    }
135	
136	    setContracts(data || []);
137	    setLoading(false);
138	  };
139	
140	  useEffect(() => {
141	    fetchContracts();
142	  }, [workspaceId]);
143	
144	  const handleDelete = async (id: string) => {
145	    const { error } = await supabase.from("contracts").delete().eq("id", id);
146	    if (error) {
147	      toast.error("Failed to delete contract");
148	      return;
149	    }
150	    toast.success("Contract deleted");
151	    fetchContracts();
152	  };
153	
154	  const handleDuplicate = async (contract: Contract) => {
155	    const { data: { session } } = await supabase.auth.getSession();
156	    if (!session) return;
157	
158	    const { error } = await supabase.from("contracts").insert({
159	      user_id: session.user.id,
160	      title: `${contract.title} (Copy)`,
161	      client_name: contract.client_name,
162	      client_email: contract.client_email,
163	      contract_type: contract.contract_type,
164	      content: contract.content,
165	      deliverables: contract.deliverables,
166	      payment_terms: contract.payment_terms,
167	      exclusivity: contract.exclusivity,
168	      exclusivity_details: contract.exclusivity_details,
169	      usage_rights: contract.usage_rights,
170	      termination_clause: contract.termination_clause,
171	      value: contract.value,
172	      currency: contract.currency,
173	      status: "draft",
174	    });
175	
176	    if (error) {
177	      toast.error("Failed to duplicate contract");
178	      return;
179	    }
180	    toast.success("Contract duplicated");
181	    fetchContracts();
182	  };
183	
184	  const handleStatusChange = async (id: string, status: string) => {
185	    const { error } = await supabase
186	      .from("contracts")
187	      .update({ status })
188	      .eq("id", id);
189	
190	    if (error) {
191	      toast.error("Failed to update status");
192	      return;
193	    }
194	    toast.success(`Status updated to ${status}`);
195	    fetchContracts();
196	  };
197	
198	  const handleFileUpload = async (file: File, contractType: string, title: string) => {
199	    const { data: { session } } = await supabase.auth.getSession();
200	    if (!session) return;
201	
202	    const fileExt = file.name.split(".").pop()?.toLowerCase();
203	    
204	    let content = "";
205	
206	    // For text-based files, read the content directly for editing
207	    if (fileExt === "txt" || fileExt === "md") {
208	      content = await file.text();
209	    } else {
210	      // For PDF, DOCX, etc. — upload to storage and create editable content
211	      const storagePath = `${session.user.id}/${Date.now()}-${file.name}`;
212	      
213	      const { error: uploadError } = await supabase.storage
214	        .from("contract-uploads")
215	        .upload(storagePath, file);
216	
217	      if (uploadError) {
218	        toast.error("Failed to upload file: " + uploadError.message);
219	        return;
220	      }
221	
222	      content = `[Original file: ${file.name}]\n[File type: ${file.type || fileExt}]\n[Uploaded: ${new Date().toLocaleString()}]\n\n---\n\nYou can edit this contract content below. The original document has been securely stored.\n\n---\n\n[Add or paste your contract terms here]`;
223	    }
224	
225	    const { data, error } = await supabase.from("contracts").insert({
226	      user_id: session.user.id,
227	      title,
228	      client_name: "To be specified",
229	      contract_type: contractType,
230	      content,
231	      status: "draft",
232	      currency: "KES",
233	    }).select().single();
234	
235	    if (error) {
236	      toast.error("Failed to create contract record");
237	      return;
238	    }
239	
240	    toast.success("Contract uploaded! You can now edit all details.");
241	    fetchContracts();
242	    
243	    // Open the edit dialog immediately so user can fill in details
244	    if (data) {
245	      setEditingContract(data as Contract);
246	    }
247	  };
248	
249	  const formatCurrency = (amount: number | null, currency: string) => {
250	    if (!amount) return "—";
251	    return new Intl.NumberFormat("en-KE", {
252	      style: "currency",
253	      currency: currency || "KES",
254	    }).format(amount);
255	  };
256	
257	  const filteredContracts = contracts
258	    .filter((contract) => {
259	      const matchesSearch = contract.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
260	        contract.client_name.toLowerCase().includes(searchQuery.toLowerCase());
261	      const matchesStatus = statusFilter === "all" || contract.status === statusFilter;
262	      return matchesSearch && matchesStatus;
263	    })
264	    .sort((a, b) => {
265	      if (sortBy === "value") return (Number(b.value) || 0) - (Number(a.value) || 0);
266	      if (sortBy === "oldest") return new Date(a.created_at).getTime() - new Date(b.created_at).getTime();
267	      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
268	    });
269	
270	  const stats = {
271	    total: contracts.length,
272	    active: contracts.filter((c) => c.status === "active" || c.status === "signed").length,
273	    pending: contracts.filter((c) => c.status === "sent" || c.status === "draft").length,
274	    totalValue: contracts.filter(c => c.status !== "cancelled").reduce((acc, c) => acc + (Number(c.value) || 0), 0),
275	  };
276	
277	  if (loading) {
278	    return (
279	      <div className="mx-auto w-full max-w-6xl space-y-8 p-4 md:p-8">
280	        <div className="animate-pulse space-y-8">
281	          <div className="h-10 bg-muted rounded-2xl w-1/3" />
282	          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
283	            {[...Array(4)].map((_, i) => (
284	              <div key={i} className="h-24 bg-muted rounded-2xl" />
285	            ))}
286	          </div>
287	          <div className="h-12 bg-muted rounded-2xl" />
288	          {[...Array(3)].map((_, i) => (
289	            <div key={i} className="h-20 bg-muted rounded-2xl" />
290	          ))}
291	        </div>
292	      </div>
293	    );
294	  }
295	
296	  return (
297	    <div className="mx-auto w-full max-w-6xl min-w-0 space-y-6 p-4 md:p-8 xl:max-w-7xl">
298	
299	      {/* Header — Clean & Minimal */}
300	      <motion.div 
301	        initial={{ opacity: 0, y: 8 }}
302	        animate={{ opacity: 1, y: 0 }}
303	        className="flex flex-col md:flex-row md:items-end justify-between gap-4"
304	      >
305	        <div>
306	          <h2 className="font-vollkorn text-3xl md:text-4xl font-bold text-foreground tracking-tight">
307	            Contracts
308	          </h2>
309	          <p className="text-sm text-muted-foreground mt-1">
310	            Professional agreements, e-signatures & document management
311	          </p>
312	        </div>
313	        <div className="flex items-center gap-2">
314	          <Button
315	            variant="outline"
316	            onClick={() => setUploadDialogOpen(true)}
317	            className="gap-2 h-10 rounded-xl border-dashed hover:border-bronze/50 hover:bg-bronze/5 transition-all"
318	          >
319	            <Upload className="h-4 w-4" />
320	            <span className="hidden sm:inline">Upload</span>
321	          </Button>
322	          <Button
323	            // onClick={() => setCreateDialogOpen(true)}
324	            onClick={async () => {
325	              if (isFree) {
326	                const { count } = await supabase
327	                  .from("contracts")
328	                  .select("*", { count: "exact", head: true });
329	                if ((count || 0) >= limits.contractsPerMonth) {
330	                  toast.error("You've reached your free plan limit of 5 contracts. Upgrade to Pro for unlimited contracts.");
331	                return;
332	              }
333	            } 
334	            setCreateDialogOpen(true);
335	          }}
336	            className="gap-2 h-10 rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20 transition-all hover:shadow-xl hover:shadow-primary/30"
337	          >
338	            <Plus className="h-4 w-4" />
339	            New Contract
340	          </Button>
341	        </div>
342	      </motion.div>
343	
344	      {/* Stats — Glass Morphism Cards */}
345	      <motion.div 
346	        initial={{ opacity: 0, y: 12 }}
347	        animate={{ opacity: 1, y: 0 }}
348	        transition={{ delay: 0.05 }}
349	        className="grid grid-cols-1 gap-3 sm:grid-cols-2 xl:grid-cols-4"
350	      >
351	        {[
352	          { label: "Total", value: stats.total, icon: <File className="h-4 w-4" />, accent: "primary" },
353	          { label: "Active", value: stats.active, icon: <CheckCircle2 className="h-4 w-4" />, accent: "emerald" },
354	          { label: "Pending", value: stats.pending, icon: <Clock className="h-4 w-4" />, accent: "amber" },
355	          { label: "Value", value: formatCurrency(stats.totalValue, "KES"), icon: <TrendingUp className="h-4 w-4" />, accent: "blue" },
356	        ].map((stat, i) => (
357	          <div
358	            key={stat.label}
359	            className="relative group p-4 rounded-2xl border border-border/50 bg-card hover:border-border transition-all overflow-hidden"
360	          >
361	            <div className={`absolute inset-0 bg-gradient-to-br opacity-0 group-hover:opacity-100 transition-opacity duration-500 ${
362	              stat.accent === "primary" ? "from-primary/5 to-transparent" :
